section.code:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://faion.net/schemas/ruby-rails-patterns.json",
  "type": "object",
  "required": ["service_result_class_count", "services", "verify_authorized_enabled", "ci_gates"],
  "properties": {
    "service_result_class_count": {"type": "integer", "minimum": 1, "maximum": 1},
    "services": {
      "type": "array",
      "minItems": 1,
      "items": {
        "type": "object",
        "required": ["class", "params_kwarg", "current_user_kwarg", "returns_service_result"],
        "properties": {
          "class": {"type": "string", "pattern": "Service$"},
          "params_kwarg": {"type": "boolean", "const": true},
          "current_user_kwarg": {"type": "boolean", "const": true},
          "returns_service_result": {"type": "boolean", "const": true}
        }
      }
    },
    "verify_authorized_enabled": {"type": "boolean", "const": true},
    "ci_gates": {
      "type": "object",
      "required": ["bullet", "brakeman", "bundler_audit"],
      "properties": {
        "bullet": {"type": "boolean", "const": true},
        "brakeman": {"type": "boolean", "const": true},
        "bundler_audit": {"type": "boolean", "const": true}
      }
    },
    "forbidden_patterns_found": {"type": "array", "items": {"type": "string"}, "maxItems": 0}
  }
}
